import{_ as t,a,b as d,c as n}from"./chunks/授权后复制刷新令牌.DFAJxpN4.js";import{_ as o,o as s,c as i,a2 as r}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Yandex चैनल जोड़ना","description":"","frontmatter":{},"headers":[],"relativePath":"hi/upload/yandex.md","filePath":"hi/upload/yandex.md","lastUpdated":1781962217000}'),l={name:"hi/upload/yandex.md"};function p(c,e,h,u,m,x){return s(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="yandex-चैनल-जोड़ना" tabindex="-1">Yandex चैनल जोड़ना <a class="header-anchor" href="#yandex-चैनल-जोड़ना" aria-label="Permalink to &quot;Yandex चैनल जोड़ना&quot;">​</a></h1><h2 id="पहले-क्या-चाहिए" tabindex="-1">पहले क्या चाहिए <a class="header-anchor" href="#पहले-क्या-चाहिए" aria-label="Permalink to &quot;पहले क्या चाहिए&quot;">​</a></h2><table tabindex="0"><thead><tr><th>ज़रूरत</th><th>क्यों चाहिए</th></tr></thead><tbody><tr><td>Yandex account</td><td>sign in और Yandex Disk authorize करने के लिए</td></tr><tr><td>Yandex OAuth app</td><td><code>Client ID</code> और <code>Client Secret</code> generate करने के लिए</td></tr><tr><td>आपका ImgBed domain</td><td>OAuth redirect URI के लिए</td></tr><tr><td>उपलब्ध Yandex Disk storage</td><td>असली file storage location</td></tr></tbody></table><h2 id="setup-steps" tabindex="-1">Setup Steps <a class="header-anchor" href="#setup-steps" aria-label="Permalink to &quot;Setup Steps&quot;">​</a></h2><h3 id="step-1-yandex-oauth-app-बनाएँ" tabindex="-1">Step 1: Yandex OAuth App बनाएँ <a class="header-anchor" href="#step-1-yandex-oauth-app-बनाएँ" aria-label="Permalink to &quot;Step 1: Yandex OAuth App बनाएँ&quot;">​</a></h3><ol><li>Yandex OAuth app creation page खोलें:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://oauth.yandex.com/client/new</span></span></code></pre></div><ol start="2"><li>अगर sign in पर redirect हो, तो पहले Yandex account से sign in करें।</li><li>नया app बनाएँ।</li><li>app को पहचानने लायक नाम दें, जैसे <code>imgbed-yandex</code>।</li><li>callback या redirect URL settings खोजें।</li><li>डालें:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/api/oauth/yandex/callback</span></span></code></pre></div><h3 id="step-2-permissions-confirm-करें" tabindex="-1">Step 2: Permissions confirm करें <a class="header-anchor" href="#step-2-permissions-confirm-करें" aria-label="Permalink to &quot;Step 2: Permissions confirm करें&quot;">​</a></h3><p>मौजूदा ImgBed Yandex integration के लिए <code>Yandex.Disk REST API</code> के तहत ये चार permissions रखें:</p><table tabindex="0"><thead><tr><th>Permission</th><th>Purpose</th></tr></thead><tbody><tr><td><code>cloud_api:disk.app_folder</code></td><td>ImgBed को app folder में files store करने देता है</td></tr><tr><td><code>cloud_api:disk.read</code></td><td>files और download links पढ़ता है</td></tr><tr><td><code>cloud_api:disk.write</code></td><td>files upload, folders create और files delete करता है</td></tr><tr><td><code>Access to information about Yandex.Disk</code></td><td>disk quota और used space पढ़ता है</td></tr></tbody></table><p>अगर <code>Yandex ID API</code> में ये permissions दिखें, तो वे optional हैं:</p><table tabindex="0"><thead><tr><th>Permission Text</th><th>Recommendation</th></tr></thead><tbody><tr><td><code>Access to username, first name and surname, gender</code></td><td>optional</td></tr><tr><td><code>Access to email address</code></td><td>optional</td></tr></tbody></table><p>core upload, download, deletion और quota features मुख्य रूप से ऊपर की चार <code>Yandex.Disk REST API</code> permissions पर निर्भर हैं।</p><p><img src="'+t+'" alt="Yandex Disk permissions configure करें" loading="lazy"></p><h3 id="step-3-app-credentials-copy-करें" tabindex="-1">Step 3: App Credentials copy करें <a class="header-anchor" href="#step-3-app-credentials-copy-करें" aria-label="Permalink to &quot;Step 3: App Credentials copy करें&quot;">​</a></h3><p>app बनने के बाद copy करें:</p><table tabindex="0"><thead><tr><th>Yandex Field</th><th>ImgBed Field</th></tr></thead><tbody><tr><td><code>Client ID</code></td><td><code>Client ID</code></td></tr><tr><td><code>Client Secret</code></td><td><code>Client Secret</code></td></tr></tbody></table><p><img src="'+a+'" alt="Client ID और Secret record करें" loading="lazy"></p><h3 id="step-4-yandex-channel-भरें" tabindex="-1">Step 4: Yandex channel भरें <a class="header-anchor" href="#step-4-yandex-channel-भरें" aria-label="Permalink to &quot;Step 4: Yandex channel भरें&quot;">​</a></h3><p>Upload Settings में <code>Yandex</code> चुनें और भरें:</p><table tabindex="0"><thead><tr><th>ImgBed Field</th><th>क्या डालें</th></tr></thead><tbody><tr><td>Channel name</td><td>पहचानने लायक नाम, जैसे <code>Main Yandex</code></td></tr><tr><td>Client ID</td><td>Yandex app <code>Client ID</code></td></tr><tr><td>Client Secret</td><td>Yandex app <code>Client Secret</code></td></tr><tr><td>Refresh Token</td><td>अभी खाली छोड़ें</td></tr><tr><td>Root directory</td><td>optional। default <code>imgbed</code>।</td></tr></tbody></table><p><img src="'+d+'" alt="Channel config edit करें" loading="lazy"></p><h3 id="step-5-refresh-token-लें" tabindex="-1">Step 5: Refresh Token लें <a class="header-anchor" href="#step-5-refresh-token-लें" aria-label="Permalink to &quot;Step 5: Refresh Token लें&quot;">​</a></h3><ol><li>ImgBed में <code>Get Token</code> पर क्लिक करें।</li><li>जिस Yandex account को connect करना है उससे sign in करें।</li><li>authorization prompt approve करें।</li><li>callback page <code>Refresh Token</code> दिखाएगा।</li><li>इसे copy करें।</li><li>ImgBed में लौटकर <code>Refresh Token</code> field में paste करें।</li></ol><p><img src="'+n+`" alt="Authorization के बाद refresh token copy करें" loading="lazy"></p><h3 id="step-6-channel-save-करें" tabindex="-1">Step 6: Channel save करें <a class="header-anchor" href="#step-6-channel-save-करें" aria-label="Permalink to &quot;Step 6: Channel save करें&quot;">​</a></h3><p>सभी fields भरने के बाद channel save करें।</p><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Yandex OAuth Console खोलें</span></span>
<span class="line"><span>-&gt; app बनाएँ</span></span>
<span class="line"><span>-&gt; https://your-domain.com/api/oauth/yandex/callback जोड़ें</span></span>
<span class="line"><span>-&gt; Yandex Disk permissions confirm करें</span></span>
<span class="line"><span>-&gt; Client ID और Client Secret copy करें</span></span>
<span class="line"><span>-&gt; ImgBed में Client ID / Client Secret भरें</span></span>
<span class="line"><span>-&gt; Get Token क्लिक करें</span></span>
<span class="line"><span>-&gt; callback page से Refresh Token copy करें</span></span>
<span class="line"><span>-&gt; ImgBed में paste करके save करें</span></span></code></pre></div><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ol><li>Register a Yandex app: <a href="https://yandex.com/dev/id/doc/en/register-client" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/register-client</a></li><li>Get an authorization code through URL: <a href="https://yandex.com/dev/id/doc/en/codes/code-url" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/codes/code-url</a></li><li>Yandex OAuth token endpoint: <a href="https://yandex.com/dev/id/doc/en/tokens/token" target="_blank" rel="noreferrer">https://yandex.com/dev/id/doc/en/tokens/token</a></li></ol>`,33)])])}const k=o(l,[["render",p]]);export{f as __pageData,k as default};
